int a = 10;
int b = 3;

int sum = a + b;       // 13
int product = a * b;   // 30

// Integer Division (Drops the decimal!)
int division = a / b;  // 3 (Not 3.333!)

// Modulus (The Remainder)
int remainder = a % b; // 1 (Because 3 goes into 10 three times, with 1 left over)

int health = 100;

// The Legacy Way:
health = health - 20;

// The Compound Shorthand Way:
health -= 20; // Does the exact same thing!

health *= 2;  // Multiplies current health by 2
health %= 3;  // Divides current health by 3 and saves the remainder

