int hp = 50;
boolean hasShield = true;

// Logical AND (&&) - BOTH sides must be true
if (hp > 0 && hasShield == true) {
    System.out.println("Player is safe.");
}

// Logical OR (||) - ONLY ONE side needs to be true
if (hp < 10 || hasShield == false) {
    System.out.println("Warning: Vulnerable!");
}

// Logical NOT (!) - Reverses the boolean value
if (!hasShield) { 
    System.out.println("Equip a shield immediately!");
}

String username = null;

// THE SHORT-CIRCUIT SAVE:
// Because username is null, 'username != null' is FALSE.
// Since it is an && (AND) operator, Java knows the whole statement 
// MUST be false. It skips the right side entirely!
if (username != null && username.length() > 0) {
    System.out.println("Valid username.");
}

// THE CRASH TRAP (Using a single &):
// A single & forces Java to check BOTH sides no matter what.
// Checking .length() on a null variable causes a NullPointerException!
if (username != null & username.length() > 0) { // CRASHES!
    System.out.println("Valid username.");
}

// SCENARIO A: Prefix (++x or --x)
// Rule: Update the memory FIRST, then use the variable.
int a = 10;
int b = ++a; 
System.out.println("A: " + a + " B: " + b); 
// Output: A: 11 B: 11

// SCENARIO B: Postfix (x++ or x--)
// Rule: Use the original variable FIRST, then update memory in the background.
int x = 10;
int y = x--; // Notice the decrement!
System.out.println("X: " + x + " Y: " + y); 
// Output: X: 9 Y: 10

int myScore = 85;

// The Legacy if-else Way:
String status;
if (myScore >= 50) {
    status = "Pass";
} else {
    status = "Fail";
}

// The Modern Ternary Way:
// Syntax: variable = (Condition) ? TrueValue : FalseValue;
String modernStatus = (myScore >= 50) ? "Pass" : "Fail";

System.out.println("Result: " + modernStatus);

int whole = 5;
double decimal = 2.0;

// result is 2.5 (The int '5' is promoted to '5.0')
double result = whole / decimal;

int x = 5;  // Binary: 0101
int y = 3;  // Binary: 0011

// Bitwise AND (&): 0001 (Decimal 1)
int andResult = x & y;

// Bitwise OR (|): 0111 (Decimal 7)
int orResult = x | y;

// Left Shift (<<): Shifts bits left (Multiply by 2)
int shiftLeft = x << 1; // Result: 1010 (Decimal 10)
